const psyBull=
  (contrarian==='FADE_FEAR'?40:0)+
  (divergence==='BULLISH_SMART_VS_RETAIL'?35:0)+
  (['PANIC','CAPITULATION','DESPERATION'].includes(emotion)?25:0)+
  (analogue.action==='ACCUMULATE_LONG'||analogue.action==='BUY_THE_PANIC'?20:0);
const psyBear=
  (contrarian==='FADE_GREED'?40:0)+
  (divergence==='BEARISH_SMART_VS_RETAIL'?35:0)+
  (['EUPHORIA','EXTREME_GREED'].includes(emotion)?25:0)+
  (analogue.action==='REDUCE_LONG / SHORT_BIAS'?20:0);
const psySignal=psyBull>psyBear&&psyBull>30?'CONTRARIAN_BUY':psyBear>psyBull&&psyBear>30?'CONTRARIAN_SELL':'FOLLOW_QUANT';

return [{json:{emotion,emotionEmoji,cyclePos,cyclePhase,contrarian,contrStrength,contrSignal,biases,analogue,smartMoney,retail,divergence,divergenceSignal,crowdNext,psyBullScore:psyBull,psyBearScore:psyBear,psySignal}}];

const dec = $('Decision Gate').first().json;
const tf = $('MTF Analysis').first().json;
const reg = $('Regime Detection').first().json;
const pred = $('Prediction Engine').first().json;
const risk = $('Risk Engine').first().json;
const strat = $('Strategy Scoring').first().json;
const news = $('News Sentiment').first().json;
const psy = $('Psychology Engine').first().json;
const ms = $('Microstructure').first().json;
const pat = $('Pattern Recognition').first().json;
const pastRaw = $('Read Past Signals').first().json;
const memories = (pastRaw && pastRaw.memories) ? pastRaw.memories : [];
const cryptoMems = memories.filter(m => m.source === 'crypto_specialist_v3' || (m.tags && m.tags.includes('crypto_signal'))).slice(0, 8);
const h = tf && tf.tf1h ? tf.tf1h : {};
const price = tf && tf.price ? tf.price : 0;
const dateStr = new Date().toISOString().slice(0, 16);

// EARLY EXIT: skip Claude when no-trade score is high - saves 120s polling
if (dec.skipClaude === true) {
  return [{ json: {
    type: 'skip',
    skip: true,
    skipReason: 'DO_NOT_TRADE: no-trade score ' + dec.noTradeScore + '% (>=72%) with WAIT signal - conserving resources',
    session_id: 'skip-' + dateStr.replace(/[^0-9]/g,'')
  }}];
}

const fundRaw = $('Fetch Funding').first().json;
const fundT = fundRaw && fundRaw.tickers && fundRaw.tickers[0];
const fundingRate = fundT ? parseFloat(fundT.fundingRate || 0) * 100 : null;
const openInterest = fundT ? Math.round(fundT.openInterest || 0) : null;
const fundCtx = fundingRate !== null
  ? 'Funding: ' + (fundingRate >= 0 ? '+' : '') + fundingRate.toFixed(4) + '% (longs ' + (fundingRate > 0.01 ? 'PAYING-crowded long' : fundingRate < -0.01 ? 'EARNING-crowded short' : 'balanced') + ') | OI: $' + (openInterest / 1e6).toFixed(1) + 'M'
  : 'Funding: unavailable';
const ethRaw2 = $('Fetch ETH').first().json;
const ethR2 = ethRaw2 && ethRaw2.result ? ethRaw2.result : {};
const ethKey2 = Object.keys(ethR2)[0];
const ethT2 = ethR2[ethKey2] || {};
const ethPrice2 = ethT2.c ? parseFloat(ethT2.c[0]) : 0;
const ethOpen2 = ethT2.o ? parseFloat(ethT2.o[1]) : 0;
const ethChg2 = ethOpen2 > 0 ? Math.round(((ethPrice2 - ethOpen2) / ethOpen2) * 10000) / 100 : 0;
const ethCtx = ethPrice2 > 0 ? 'ETH/USD: $' + Math.round(ethPrice2) + ' (' + (ethChg2 >= 0 ? '+' : '') + ethChg2 + '% 24H) - ' + (ethChg2 > 1.5 ? 'CONFIRMING BTC bull' : ethChg2 < -1.5 ? 'CONFIRMING BTC bear' : 'DIVERGING from BTC') : 'ETH: unavailable';

const lastMem = cryptoMems[0] ? cryptoMems[0].content || '' : '';
const wc = [];
const lcDir = (lastMem.match(/TRADE SIGNAL[^:]*:\s*(\w+)\s+BTC/) || [])[1];
const lcRSI = parseFloat((lastMem.match(/RSI:([\d.]+)/) || [])[1] || 0);
const lcRegime = (lastMem.match(/Regime:(\w+)/) || [])[1];
const lcPrice = parseInt(((lastMem.match(/@\s*\$([\d,]+)/) || [])[1] || '0').replace(/,/g,''));
if (lcDir && lcDir !== dec.direction) wc.push('Direction: ' + lcDir + ' -> ' + dec.direction);
if (lcRegime && lcRegime !== reg.regime) wc.push('Regime: ' + lcRegime + ' -> ' + reg.regime);
if (lcRSI && Math.abs(lcRSI - (h.rsi || 50)) > 4) wc.push('RSI: ' + lcRSI + ' -> ' + h.rsi);
if (lcPrice && Math.abs(lcPrice - Math.round(price)) > 300) wc.push('Price: $' + lcPrice + ' -> $' + Math.round(price));
const whatChanged = wc.length > 0 ? 'CHANGED: ' + wc.join(' | ') : 'Stable: no significant changes from last cycle';

const histContext = cryptoMems.length > 0
  ? 'VAULT HISTORICAL SIGNALS (last ' + cryptoMems.length + '):\n' + cryptoMems.map(m => '- ' + (m.content || '').slice(0, 180)).join('\n')
  : 'No historical signals stored yet - this is the first cycle.';

const prompt = 'You are the PRIMARY INTELLIGENCE of a Crypto Specialist Super Agent monitoring BTC/USD 24/7.\n\n' + histContext + '\n\nCURRENT CYCLE - ' + dateStr + ' UTC:\nSIGNAL: ' + dec.direction + ' | Confidence: ' + dec.confidence + '% | Regime: ' + reg.regime + '\nPrice: $' + Math.round(price) + ' | RSI(1H): ' + h.rsi + ' | MACD cross: ' + (h.macd && h.macd.cross) + ' | Hurst: ' + h.hurst + '(' + h.hurstR + ')\nEMA trend: ' + (h.ema && h.ema.bull ? 'BULLISH' : 'BEARISH') + ' | Choppiness: ' + (h.isChoppy ? 'CHOPPY' : 'TRENDING') + ' | Z-score: ' + h.zScore + '\nStrategy bull/bear: ' + strat.bullTotal + '/' + strat.bearTotal + '\nBayesian prob: ' + Math.round((pred.bayesianProb||0)*100) + '% | MC 24H expected: ' + (pred.monteCarlo && pred.monteCarlo.expRet) + '% | VaR(95%): -' + risk.var95 + '%\n' + fundCtx + '\n' + ethCtx + '\n' + whatChanged + '\nQuorum: ' + dec.quorum + '/10 families agree | No-Trade Score: ' + dec.noTradeScore + '%' + (dec.decayApplied ? ' | DECAY ACTIVE' : '') + (dec.newsShock ? ' | NEWS SHOCK ACTIVE' : '') + '\nKelly size: ' + risk.kellyPct + '% | EV: ' + risk.ev + ' | ATR%: ' + h.atrPct + '\nWyckoff: ' + pat.wyckoff + ' | SMC BOS: ' + (pat.smc && pat.smc.bos) + '\nNews: ' + (news && news.signal) + ' | Score: ' + (news && news.score) + ' | Themes: ' + ((news && news.themes || []).join(', ')) + '\nPsychology: ' + psy.emotion + '(pos:' + psy.cyclePos + ') | Analogue: ' + (psy.analogue && psy.analogue.period) + '\n\nTASK - 3 sharp, non-obvious insights:\n1. PATTERN RECOGNITION: What historical pattern does this MOST resemble? What happened next?\n2. RISK VECTOR: What is the single biggest risk to this ' + dec.direction + ' signal RIGHT NOW?\n3. EDGE: What specific confluence makes this signal higher/lower quality than average?\n\nMax 4 sentences per insight. Be precise. Reference the numbers.';

return [{ json: { type: 'claude_pro', skip: false, payload: { prompt }, session_id: 'n8n-crypto-' + dateStr.replace(/[^0-9]/g,'') } }];

const https = require('https');
const crypto = require('crypto');
const liveTrading = $env.ENABLE_LIVE_TRADING || 'false';
const signal = $('Format Alert').first().json.signal || 'HOLD';
const confidence = parseFloat($('Format Alert').first().json.confidence || 0);
const minConf = parseFloat($env.TRADE_MIN_CONFIDENCE || '75');
if (liveTrading !== 'true') {
  return [{ json: { status: 'PAPER_ONLY', message: 'Set ENABLE_LIVE_TRADING=true in n8n Railway vars to execute real trades', signal, confidence, minConf } }];
}
if (!['BUY', 'SELL'].includes(signal) || confidence < minConf) {
  return [{ json: { status: 'SKIPPED', reason: `Signal=${signal} confidence=${confidence}% need>=${minConf}%` } }];
}
const balanceData = $('Fetch Balance').first().json;
const xbtBal = parseFloat((balanceData && balanceData.result && balanceData.result.XXBT) || 0);
const usdBal = parseFloat((balanceData && balanceData.result && balanceData.result.ZUSD) || 0);
const price = ($('MTF Analysis').first().json.price) || 80000;
const sizePct = parseFloat($env.TRADE_SIZE_PCT || '5') / 100;
let volume;
if (signal === 'BUY') {
  volume = ((usdBal * sizePct) / price).toFixed(8);
} else {
  volume = (xbtBal * sizePct).toFixed(8);
}
if (parseFloat(volume) < 0.0001) {
  return [{ json: { status: 'SKIPPED', reason: 'Volume below Kraken minimum (0.0001 BTC)', xbtBal, usdBal } }];
}
const apiKey = $env.CRYPT_API_KEY || '';
const apiSecret = $env.CRYPT_PRIVATE_KEY || '';
const nonce = Date.now().toString();
const path = '/0/private/AddOrder';
const bodyStr = `nonce=${nonce}&pair=XBTUSD&type=${signal === 'BUY' ? 'buy' : 'sell'}&ordertype=market&volume=${volume}`;
const sha256Hash = crypto.createHash('sha256').update(nonce + bodyStr).digest();
const mac = crypto.createHmac('sha512', Buffer.from(apiSecret, 'base64'));
mac.update(Buffer.from(path));
mac.update(sha256Hash);
const sig = mac.digest('base64');
const result = await new Promise((resolve, reject) => {
  const req = https.request({ hostname: 'api.kraken.com', path, method: 'POST', headers: { 'API-Key': apiKey, 'API-Sign': sig, 'Content-Type': 'application/x-www-form-urlencoded', 'Content-Length': Buffer.byteLength(bodyStr) } }, (res) => {
    let d = ''; res.on('data', c => d += c); res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({ error: [d] }); } });
  });
  req.on('error', e => resolve({ error: [e.message] }));
  req.write(bodyStr); req.end();
});
return [{ json: { status: (result.error && result.error.length) ? 'ERROR' : 'EXECUTED', signal, volume, price, orderId: (result.result && result.result.txid && result.result.txid[0]) || null, orderDesc: (result.result && result.result.descr && result.result.descr.order) || null, krakenError: (result.error && result.error[0]) || null, confidence, timestamp: new Date().toISOString() } }];

const https = require("https");

// SKIP CHECK: if no-trade score was high, bypass Claude polling entirely
const promptData = $("Prepare Claude Prompt").first().json;
if (promptData.skip === true) {
  return [{json:{
    analysis: promptData.skipReason || 'DO_NOT_TRADE: high no-trade score - system conserving resources this cycle.',
    model_used: 'skipped',
    routed_by: 'no-trade-gate'
  }}];
}

const sub = $("Submit to Claude CLI").first().json;
const taskId = sub.task_id;
if (!taskId) {
  return [{json:{analysis:"Task submission failed: "+JSON.stringify(sub),model_used:"error",routed_by:"inspiring-cat"}}];
}
for (let i=0;i<40;i++) {
  await new Promise(r=>setTimeout(r,3000));
  const poll = await new Promise((resolve,reject)=>{
    https.get("https://inspiring-cat-production.up.railway.app/tasks/"+taskId,res=>{
      let body="";
      res.on("data",c=>body+=c);
      res.on("end",()=>{try{resolve(JSON.parse(body));}catch(e){resolve({status:"error",result:body});}});
    }).on("error",reject);
  });
  if (poll.status==="done") {
    return [{json:{analysis:poll.result||"Empty response",model_used:"claude-cli-pro",routed_by:"inspiring-cat/tasks"}}];
  }
  if (poll.status==="failed") {
    return [{json:{analysis:"Claude CLI failed: "+(poll.error||"unknown"),model_used:"error",routed_by:"inspiring-cat/tasks"}}];
  }
