  if(allSame&&priceMove<0.8){conf*=0.75;decayApplied=true;}
}

// NO-TRADE SCORE: 7 factors (0=none, 100=all 7 present)
// Factor 7: neutral news + technical weakness (news alone is insufficient)
const noTradeFactors=[
  h.isChoppy===true,
  (h.atrPct||50)<15,
  ms&&Math.abs(ms.imbalance||0)<5,
  !quorumPass,
  risk&&risk.rr<1.2,
  decayApplied,
  news&&news.signal==='NEUTRAL'&&(h.isChoppy||!quorumPass),
].filter(Boolean).length;
const noTradeScore=Math.round(noTradeFactors/7*100);

// SKIP CLAUDE: when no-trade score >= 72% (5+ of 7 factors) AND signal is WAIT
// Saves 120s Claude polling latency on clearly unactionable cycles
const skipClaude=noTradeScore>=72&&direction==='WAIT';

conf=parseFloat(conf.toFixed(1));
const minConf=60;
const finalDir=conf>=minConf&&direction!=='WAIT'?direction:'WAIT';
const sendAlert=finalDir!=='WAIT'||reg.regime==='EXTREME_CAUTION';
return [{json:{direction:finalDir,confidence:conf,rawScore:raw,send_alert:sendAlert,regime:reg.regime,bayesianProb:pred.bayesianProb,ev:risk.ev,rr:risk.rr,quorum,quorumPass,noTradeScore,newsShock,decayApplied,skipClaude}}];

// ââ DATA INPUTS ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ
const strat  = $('Strategy Scoring').first().json;
