const fmtN   = n => n ? Math.round(n).toLocaleString('en-US') : '?';
const fmtPct = n => n != null ? (n >= 0 ? '+' : '') + n.toFixed(1) + '%' : '?';
const bar    = (v, w=10) => { const f2 = Math.round(Math.min(Math.max(v||0,0),100)/100*w); return '\u2588'.repeat(f2)+'\u2591'.repeat(w-f2); };
