  '\uD83D\uDE80 Target2: $' + fmtN(risk.tp2) + '  (' + (risk.tp2 ? fmtPct((risk.tp2-price)/price*100) : '?') + ')',
  '\u2696\uFE0F R:R: <b>' + risk.rr + ':1</b>   EV: ' + (risk.ev>=0?'+':'') + risk.ev + '%   Win Rate: ' + risk.winRate + '%',
  '\uD83D\uDCB3 Kelly(\u00BCf): <b>' + risk.kellyPct + '%</b>   VaR(95%): \u2212' + risk.var95 + '%   CVaR: \u2212' + risk.cvar + '%',

